from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a celestial body (or person) into a single,
    fluent sentence.  The function tries to use a natural phrasing for each
    predicate and joins the resulting clauses with commas and a final “and”.
    """
    if not triples:
        return ""

    # Group triples by subject for better sentence construction
    subject_triples: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Create a mapping from subject to the main celestial body
    # This helps identify which subject is the primary one
    main_subject = None
    for subj, tlist in subject_triples.items():
        # Prefer celestial body subjects (contain numbers or are known celestial patterns)
        if any(c.isdigit() for c in subj) or any(kw in subj.lower() for kw in ['helena', 'gaussia', 'camilla', 'figneria', 'tama', 'felicitas']):
            main_subject = subj
            break
    if main_subject is None and subject_triples:
        main_subject = list(subject_triples.keys())[0]

    # Simple template mapping for common predicates
    def phrase(t: Triple, is_main: bool = False) -> str:
        subj, pred, obj = t.subject, t.predicate, t.object

        # Normalise predicate strings (remove spaces, lower‑case)
        p = pred.strip().lower()

        # Mapping of predicate to a readable clause
        if p == "discoverer":
            if is_main:
                return f"discovered by {obj}"
            return f"{subj} was discovered by {obj}"
        if p == "discovered":
            if is_main:
                return f"discovered on {obj}"
            return f"{subj} was discovered on {obj}"
        if p == "epoch":
            if is_main:
                return f"with epoch {obj}"
            return f"{subj} has epoch {obj}"
        if p == "apoapsis":
            if is_main:
                return f"an apoapsis of {obj}"
            return f"{subj} has an apoapsis of {obj}"
        if p == "periapsis":
            if is_main:
                return f"a periapsis of {obj}"
            return f"{subj} has a periapsis of {obj}"
        if p == "orbitalperiod":
            if is_main:
                return f"an orbital period of {obj}"
            return f"{subj} has an orbital period of {obj}"
        if p == "averagespeed":
            if is_main:
                return f"an average speed of {obj}"
            return f"{subj} travels at an average speed of {obj}"
        if p == "escapevelocity":
            if is_main:
                return f"an escape velocity of {obj}"
            return f"{subj} has an escape velocity of {obj}"
        if p == "mass":
            if is_main:
                return f"a mass of {obj}"
            return f"{subj} has a mass of {obj}"
        if p == "density":
            if is_main:
                return f"a density of {obj}"
            return f"{subj} has a density of {obj}"
        if p == "temperature":
            if is_main:
                return f"a temperature of {obj}"
            return f"{subj} has a temperature of {obj}"
        if p == "maximumtemperature":
            if is_main:
                return f"a maximum temperature of {obj}"
            return f"{subj} has a maximum temperature of {obj}"
        if p == "meantemperature":
            if is_main:
                return f"a mean temperature of {obj}"
            return f"{subj} has a mean temperature of {obj}"
        if p == "minimumtemperature":
            if is_main:
                return f"a minimum temperature of {obj}"
            return f"{subj} has a minimum temperature of {obj}"
        if p == "rotationperiod":
            if is_main:
                return f"a rotation period of {obj}"
            return f"{subj} has a rotation period of {obj}"
        if p == "surfacearea":
            if is_main:
                return f"a surface area of {obj}"
            return f"{subj} has a surface area of {obj}"
        if p == "absolutemagnitude":
            if is_main:
                return f"an absolute magnitude of {obj}"
            return f"{subj} has an absolute magnitude of {obj}"
        if p == "formername":
            if is_main:
                return f"formerly known as {obj}"
            return f"{subj} was formerly known as {obj}"
        if p == "birthdate":
            if is_main:
                return f"born on {obj}"
            return f"{subj} was born on {obj}"
        if p == "deathdate":
            if is_main:
                return f"died on {obj}"
            return f"{subj} died on {obj}"
        if p == "birthplace":
            if is_main:
                return f"born in {obj}"
            return f"{subj} was born in {obj}"
        if p == "deathplace":
            if is_main:
                return f"died in {obj}"
            return f"{subj} died in {obj}"
        if p == "deathcause":
            if is_main:
                return f"died of {obj}"
            return f"{subj} died of {obj}"
        if p == "nationality" or p == "stateoforigin":
            if is_main:
                return f"from {obj}"
            return f"{subj} is from {obj}"
        if p == "almamater":
            if is_main:
                return f"studied at {obj}"
            return f"{subj} studied at {obj}"
        if p == "doctoralstudent":
            if is_main:
                return f"supervised {obj}"
            return f"{subj} supervised {obj}"
        # Fallback generic wording
        return f"{subj} {pred} {obj}"

    # Build the main sentence starting with the main subject
    main_clauses = []
    for t in subject_triples.get(main_subject, []):
        main_clauses.append(phrase(t, is_main=True))

    # Build related subject information (like discoverer details)
    related_info = []
    for subj, tlist in subject_triples.items():
        if subj != main_subject:
            subj_clauses = [phrase(t, is_main=False) for t in tlist]
            related_info.append((subj, subj_clauses))

    # Construct the sentence
    if not main_clauses:
        return ""

    # Start with main subject
    sentence = f"{main_subject} "

    # Add main clauses
    if len(main_clauses) == 1:
        sentence += main_clauses[0] + "."
    else:
        sentence += ", ".join(main_clauses[:-1]) + ", and " + main_clauses[-1] + "."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

